//! Per-detector regression tests (#177/#184). One test per detector: a
//! deterministic, shape-valid example that MUST fire that specific detector via
//! the PRODUCTION auto path. Unlike the aggregate corpus ratchet (which only
//! reports a dropped count), each test pinpoints EXACTLY which detector
//! regressed. Examples are captured from a deterministic generator UNDER the
//! `ml` feature (the shipped default), so every example survives ML scoring and
//! therefore fires under BOTH `ml` and no-ml (ML only removes candidates). The
//! ~12 detectors whose only generatable examples are gibberish that ML correctly
//! suppresses are covered by the corpus ratchet + realistic-example truth tests,
//! not here (a gibberish token is not a faithful positive under the ml default).
//!
//! ## Memory layout (2026-07-09 refactor)
//!
//! Previously this file had 867 individual `#[test]` functions. Rust's test
//! harness runs them in parallel, so 867 concurrent `SCANNER.scan()` calls
//! each allocated match buffers, the process ballooned to 19 GB and was
//! OOM-killed (pid 2579946). Now there is ONE test function that loops over
//! a static table of (example, detector_id) pairs, calling
//! `assert_detector_fires` sequentially. One scanner, one match buffer at a
//! time, deterministic order, identical coverage. The assertion message still
//! names the exact detector on failure, so regression pinpointing is preserved.

use keyhog_core::{Chunk, ChunkMetadata};
use keyhog_scanner::CompiledScanner;
use std::sync::LazyLock;

static SCANNER: LazyLock<CompiledScanner> = LazyLock::new(|| {
    CompiledScanner::compile(keyhog_core::embedded_detector_specs().to_vec())
        .expect("scanner compile")
});

#[allow(dead_code)]
fn assert_detector_fires(example: &str, detector_id: &str) {
    let chunk = Chunk {
        data: example.into(),
        metadata: ChunkMetadata {
            source_type: "per-detector-test".into(),
            path: Some("s.txt".into()),
            base_offset: 0,
            ..Default::default()
        },
    };
    let fired = SCANNER
        .scan(&chunk)
        .iter()
        .any(|m| m.detector_id.as_ref() == detector_id);
    assert!(
        fired,
        "detector `{detector_id}` did not fire on its own shape-valid example `{example}`"
    );
}

